array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=$HOME/Library/Logs/researchman-ideas.log;
[ -f $LOG ] && [ $(stat -f%z $LOG) -gt 5242880 ] && mv $LOG $LOG.1;
node scripts/run-if-due.mjs --state .last-idea-seeds-run.txt --daily-at 10 >> $LOG 2>&1 || exit 0;
# 収集2本（autoresearch/techresearch）と同じ排他ロックで直列化（CLI同時実行を避ける）。
# ロックが90分超残存していたらkill -9等の残骸とみなし奪取する（3ジョブ合計でも90分あれば完走する）
LOCK=/tmp/researchman-git.lock; waited=0;
while ! mkdir $LOCK 2>/dev/null; do
  if [ -d $LOCK ] && [ $(( $(date +%s) - $(stat -f %m $LOCK) )) -gt 5400 ]; then
    echo "staleロック奪取: $(date)" >> $LOG; rmdir $LOCK 2>/dev/null; continue;
  fi;
  sleep 30; waited=$((waited+30));
  [ $waited -ge 2700 ] && { echo "ロック取得タイムアウト: $(date)" >> $LOG; exit 0; };
done;
trap "rmdir $LOCK 2>/dev/null" EXIT;
echo "===== Idea seeds start: $(date) =====" >> $LOG;
if node scripts/generate-idea-seeds.mjs >> $LOG 2>&1; then
  node scripts/notify-line.mjs --text-file /tmp/researchman-idea-seeds.txt >> $LOG 2>&1;
else
  echo "生成エラー終了: $(date)" >> $LOG;
  node scripts/run-if-due.mjs --state .last-idea-seeds-run.txt --mark >> $LOG 2>&1;
  node scripts/notify-line.mjs --result error --label IdeaSeeds >> $LOG 2>&1;
fi;
echo "Idea seeds completed: $(date)" >> $LOG
